-smoothing: auto !important;\n}\n.reports-list {\n            list-style: none;\n            padding: 0;\n            margin: 0;\n        }\n.reports-list li {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 15px;\n            color: #000864;\n            padding: 10px 0;\n            border-bottom: 1px solid #e2e8f0;\n            display: flex;\n            align-items: center;\n            gap: 10px;\n            line-height: 1.6;\n            -webkit-font-smoothing: auto;\n        }\n.reports-list li:last-child {\n            border-bottom: none;\n        }\n.reports-list .report-icon {\n            color: #00AFF0;\n            flex-shrink: 0;\n            font-size: 14px;\n        \n            -webkit-font-smoothing: auto !important;\n}\n@media (max-width: 1024px) {\n            .beforeafter-grid {\n                grid-template-columns: 1fr;\n                max-width: 500px;\n                margin: 0 auto;\n            }\n            .beforeafter-arrow {\n                transform: rotate(90deg);\n                padding: 16px 0;\n            }\n            .products-grid {\n                grid-template-columns: 1fr;\n                max-width: 600px;\n                margin: 0 auto;\n            }\n            .selection-guide {\n                grid-template-columns: 1fr;\n                max-width: 400px;\n                margin: 48px auto 0;\n            }\n            .erp-compat-callout {\n                flex-direction: column;\n                align-items: center;\n                text-align: center;\n            }\n            .integration-visual {\n                flex-direction: column;\n            }\n            .integration-arrow {\n                transform: rotate(90deg);\n                padding: 8px 0;\n            }\n            .results-grid {\n                grid-template-columns: repeat(3, 1fr);\n            }\n            .reports-grid {\n                grid-template-columns: 1fr;\n                max-width: 500px;\n                margin: 0 auto;\n            }\n        }\n\n.section-header{text-align:center;margin-bottom:48px}\n.section-title{font-family:\'Noto Sans\', sans-serif;font-size:36px;font-weight:700;color:#000864;margin-bottom:16px}\n.section-subtitle{font-family:\'Noto Sans\', sans-serif;font-size:18px;color:#5b6b80;max-width:600px;margin:0 auto}\n@media (max-width:640px){.section-title{font-size:28px}.capabilities-grid{grid-template-columns:1fr;max-width:360px;margin-left:auto;margin-right:auto}.product-detail-cta-title{font-size:28px}.product-detail-cta-buttons{flex-direction:column}.product-detail-cta-buttons .btn-white,.product-detail-cta-buttons .btn-outline-white{width:100%;text-align:center}}\n.rep ul,.rep ol{list-style:none !important;padding:0 !important;margin:0 !important}.rep li{list-style:none !important}.rep li::before{display:none !important}\n\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n\n.report-icon {\n            -webkit-font-smoothing: auto !important;\n        }\n/* === FAQ: MES (THAI) === */\n.et_pb_section:has(.th-mes-faq){padding:60px 0 !important;background:#f8fafc !important}\n.th-mes-faq{-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.th-mes-faq p{padding-bottom:0;line-height:1.6}\n.et_pb_section .th-mes-faq h2{margin:0;padding:0;line-height:1.6}\n.th-mes-faq summary{-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){}\n/* === CTA: พร้อมมองเห็นสายการผลิตชัดเจนหรือยัง? === */\n.th-mes-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.th-mes-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.th-mes-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.th-mes-cta-super-d{position:absolute;top:auto;right:-5%;bottom:-5%;left:auto;width:35%;min-height:40vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;opacity:0.16;pointer-events:none;z-index:0;animation:superDGlow 3s ease-in-out infinite}\n@keyframes superDGlow{0%,100%{filter:drop-shadow(0 0 20px rgba(0,175,240,0.1))}50%{filter:drop-shadow(0 0 40px rgba(0,175,240,0.25))}}\n\n.th-mes-cta-container{position:relative;z-index:3;max-width:700px;margin:0 auto;text-align:center}\n.th-mes-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.th-mes-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:rgba(255,255,255,0.9);margin:0 0 40px}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .th-mes-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .th-mes-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .th-mes-cta-container p{padding-bottom:0 !important}\n\n.th-mes-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.th-mes-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.th-mes-cta-btn:hover::before{left:100%}\n.th-mes-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.th-mes-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.th-mes-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.th-mes-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.th-mes-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.th-mes-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .th-mes-cta-title{font-size:28px;margin-bottom:16px}\n  .th-mes-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .th-mes-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .th-mes-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.th-mes-cta-btn{transition:none !important}.th-mes-cta-btn::before{display:none}}\n\n.et_pb_section:has(.th-mes-related-section){background:#F5F7FA;padding:0}\n.th-mes-related-section{padding:60px 5%;background:#F5F7FA;max-width:100%;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto}\n.th-mes-related-heading{font-family:\'Noto Sans\',sans-serif;font-size:28px;font-weight:600;color:#000864;margin:0 0 32px 0;padding:0;text-align:center;line-height:1.6;-webkit-font-smoothing:auto}\n.th-mes-related-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:24px;max-width:1200px;margin:0 auto}\n.th-mes-related-card{display:block;padding:24px;background:#fff;border-radius:12px;text-decoration:none;border:1px solid #e5e7eb;transition:box-shadow 0.3s ease;color:#333;line-height:1.6}\n.th-mes-related-card:hover{box-shadow:0 8px 24px rgba(0,8,100,0.1)}\n.th-mes-related-card-title{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 8px 0;padding:0;line-height:1.6;-webkit-font-smoothing:auto}\n.th-mes-related-card-desc{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#666;margin:0;padding:0;line-height:1.5;-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){.th-mes-related-card{transition:none}}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="mes-hero">\n\n            <div class="mes-hero-inner">\n                <div class="mes-hero-grid">\n                    <div class="mes-hero-content">\n                        <div class="mes-hero-badge">MES (ระบบบริหารการผลิต)</div>\n                        <h1>หยุดเดา เริ่มมองเห็น</h1>\n                        <p class="mes-hero-subtitle">มองเห็นทุกสถานีงาน ทุกใบสั่งผลิต ทุกนาที แบบเรียลไทม์ รู้สิ่งที่เกิดขึ้นบนสายการผลิตของคุณ—ขณะที่มันเกิดขึ้น</p>\n                        <div class="mes-hero-ctas">\n                            <a href="../demo/" class="btn-white">พูดคุยกับเรา</a>\n                            <a href="#compare" class="btn-outline-white">ค้นหาแบบที่เหมาะกับคุณ</a>\n                        </div>\n                        <div class="mes-hero-stats">\n                            <div class="mes-hero-stat">\n                                <div class="mes-hero-stat-number dw-years">44</div>\n                                <div class="mes-hero-stat-label">ปีในอุตสาหกรรมการผลิต</div>\n                            </div>\n                            <div class="mes-hero-stat">\n                                <div class="mes-hero-stat-number">50K+</div>\n                                <div class="mes-hero-stat-label">โรงงาน</div>\n                            </div>\n                            <div class="mes-hero-stat">\n                                <div class="mes-hero-stat-number">100+</div>\n                                <div class="mes-hero-stat-label">ไซต์ในประเทศไทย</div>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="mes-hero-visual">\n                        <div class="mes-dashboard-mockup">\n                            <div class="mockup-header">\n                                <div class="mockup-dot"></div>\n                                <div class="mockup-dot"></div>\n                                <div class="mockup-dot"></div>\n                            </div>\n                            <div class="mockup-content">\n                                <div class="mockup-status-bar">\n                                    <div class="mockup-status-item">\n                                        <div class="mockup-status-value green">87%</div>\n                                        <div class="mockup-status-label">OEE</div>\n                                    </div>\n                                    <div class="mockup-status-item">\n                                        <div class="mockup-status-value">1,247</div>\n                                        <div class="mockup-status-label">ผลิตวันนี้</div>\n                                    </div>\n                                    <div class="mockup-status-item">\n                                        <div class="mockup-status-value yellow">3</div>\n                                        <div class="mockup-status-label">แจ้งเตือน</div>\n                                    </div>\n                                </div>\n                                <div class="mockup-timeline">\n                                    <div class="mockup-bar" style="height: 40%;"></div>\n                                    <div class="mockup-bar" style="height: 65%;"></div>\n                                    <div class="mockup-bar" style="height: 55%;"></div>\n                                    <div class="mockup-bar" style="height: 80%;"></div>\n                                    <div class="mockup-bar" style="height: 70%;"></div>\n                                    <div class="mockup-bar active" style="height: 90%;"></div>\n                                    <div class="mockup-bar" style="height: 45%;"></div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: MES คืออะไร? (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: MES คืออะไร? (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: MES คืออะไร? (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-section" style="padding: 40px 0 0; text-align: center;">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n        <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 22px; font-weight: 700; color: #000864; margin: 0 0 12px 0;">MES (ระบบบริหารการผลิต) คืออะไร?</h2>\n        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 17px; line-height: 1.7; color: #333; margin: 0 0 24px 0;">\n          MES (Manufacturing Execution System — ระบบบริหารการผลิต) คือซอฟต์แวร์ที่ติดตาม ตรวจสอบ และควบคุมการผลิตบนพื้นที่โรงงานแบบเรียลไทม์ เชื่อมช่องว่างระหว่างการวางแผนใน ERP กับการปฏิบัติงานจริงหน้างาน ช่วยให้ผู้ผลิตมองเห็นสิ่งที่เกิดขึ้นทุกสถานีงานและทุกใบสั่งผลิตได้ทันที — แทนที่สมุดจดและรายงานที่ล่าช้าด้วยข้อมูลสด\n        </p>\n        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 17px; line-height: 1.7; color: #333;">\n          <strong>DigiWin MES</strong> มอบการมองเห็นแบบเรียลไทม์ให้โรงงานในประเทศไทย ผ่านสามระดับ — <strong>MES</strong> สำหรับการบริหารการผลิตเต็มรูปแบบ, <strong>SFT</strong> (Shop Floor Tracking — ติดตามหน้างาน) สำหรับระดับกลาง, และ <strong>AIoT Cloud</strong> สำหรับระดับเริ่มต้น — ติดตามใบสั่งผลิต, คำนวณ OEE แบบเรียลไทม์, บันทึกข้อมูลคุณภาพทุกสถานี, และรักษาการตรวจสอบย้อนกลับระดับล็อตอย่างสมบูรณ์ เริ่มต้นจากจุดไหนก็ได้ แล้วอัปเกรดเมื่อโรงงานพร้อม\n        </p>\n      </div>    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Beforeafter (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Beforeafter (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Beforeafter (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="beforeafter-section">\n    <div class="beforeafter-inner">\n                <div class="section-header">\n                    <h2 class="section-title">การเปลี่ยนแปลง</h2>\n                    <p class="section-subtitle">จากความวุ่นวายหน้างาน สู่ความชัดเจนแบบเรียลไทม์</p>\n                </div>\n    \n                <div class="beforeafter-grid">\n                    <div class="beforeafter-column before">\n                        <div class="beforeafter-header before">\n                            <div class="beforeafter-label before">ก่อนใช้ MES</div>\n                        </div>\n                        <div class="beforeafter-content">\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">“ออเดอร์นั้นอยู่ไหน?”</div>\n                                <div class="beforeafter-item-desc">ต้องเดินไปดูหน้างาน ถามคนนั้นคนนี้ หวังว่าจะมีคนรู้ ใช้เวลาหลายชั่วโมงกว่าจะได้คำตอบ</div>\n                            </div>\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">ข้อมูลเมื่อวาน</div>\n                                <div class="beforeafter-item-desc">รายงานการผลิตมาถึงหลังจากปัญหาเกิดขึ้นแล้ว ตามแก้ตลอดเวลา</div>\n                            </div>\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">ตื่นตระหนกเรื่องตรวจสอบย้อนกลับ</div>\n                                <div class="beforeafter-item-desc">มีปัญหาคุณภาพ? ต้องค้นกระดาษหลายวันเพื่อหาว่าแบทช์ไหน ล็อตไหน พนักงานคนไหน</div>\n                            </div>\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">เดา OEE</div>\n                                <div class="beforeafter-item-desc">บันทึก Downtime บนไวท์บอร์ด ไม่มีใครเชื่อถือตัวเลข</div>\n                            </div>\n                        </div>\n                    </div>\n    \n                    <div class="beforeafter-arrow">→</div>\n    \n                    <div class="beforeafter-column after">\n                        <div class="beforeafter-header after">\n                            <div class="beforeafter-label after">ด้วย DigiWin MES</div>\n                        </div>\n                        <div class="beforeafter-content">\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">หาตำแหน่งออเดอร์ได้ในคลิกเดียว</div>\n                                <div class="beforeafter-item-desc">อยู่สถานีไหน ทำ Operation อะไร คาดว่าจะเสร็จเมื่อไหร่—ตอบได้ทันที</div>\n                            </div>\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">แดชบอร์ดเรียลไทม์</div>\n                                <div class="beforeafter-item-desc">อัตราการผลิตสด แจ้งเตือนคุณภาพ แจ้งเตือนหยุดเครื่อง ป้องกันปัญหาได้</div>\n                            </div>\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">ตรวจสอบย้อนกลับครบวงจร</div>\n                                <div class="beforeafter-item-desc">ประวัติเต็มตั้งแต่รับวัตถุดิบถึงส่งออก คลิกเดียวเห็นทุกอย่าง</div>\n                            </div>\n                            <div class="beforeafter-item">\n                                <div class="beforeafter-item-title">OEE ที่แม่นยำ</div>\n                                <div class="beforeafter-item-desc">คำนวณอัตโนมัติจากข้อมูลเครื่องจักร ตัวเลขจริงที่เชื่อถือได้</div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="products-section">\n    <div class="products-inner">\n                <div class="section-header">\n                    <h2 class="section-title">สามเส้นทางสู่การมองเห็นสายการผลิต</h2>\n                    <p class="section-subtitle">เลือกระดับที่เหมาะกับความต้องการและงบประมาณของคุณ เริ่มจากจุดไหนก็ได้ — อัปเกรดเมื่อไหร่ก็ได้</p>\n                </div>\n    \n                <div class="products-grid">\n                    <div class="product-box">\n                        <div class="product-box-header">\n                            <span class="product-box-badge full">Full MES</span>\n                            <h3 class="product-box-title">MES</h3>\n                            <p class="product-box-tagline">ระบบบริหารการผลิตเต็มรูปแบบพร้อมการควบคุมเส้นทางการผลิต</p>\n                        </div>\n                        <div class="product-box-content">\n                            <p class="product-box-desc">ความสามารถ MES ครบวงจร ครอบคลุมการจัดการใบสั่งผลิต, การควบคุมเส้นทางการผลิต, การเก็บข้อมูลคุณภาพ, และแดชบอร์ดประสิทธิภาพแบบเรียลไทม์</p>\n                            <ul class="product-features">\n                                <li><span class="check">✓</span> สั่งงานและติดตามใบสั่งผลิตแบบเรียลไทม์</li>\n                                <li><span class="check">✓</span> ควบคุมเส้นทางการผลิตพร้อมตรวจสอบ Operation</li>\n                                <li><span class="check">✓</span> เก็บข้อมูลคุณภาพเชื่อมต่อ SPC</li>\n                                <li><span class="check">✓</span> คำนวณ OEE แบบเรียลไทม์ตามเครื่อง/สาย</li>\n                                <li><span class="check">✓</span> ตรวจสอบย้อนกลับระดับล็อตและซีเรียลนัมเบอร์</li>\n                                <li><span class="check">✓</span> หน้าจอสถานีงานบนมือถือ</li>\n                            </ul>\n                            <div class="product-best-for">\n                                <div class="product-best-for-label">เหมาะสำหรับ</div>\n                                <div class="product-best-for-text">การผลิตซับซ้อนหลาย Operation, ยานยนต์/อิเล็กทรอนิกส์ที่ต้องตรวจสอบย้อนกลับ, โรงงานที่มีทุน BOI หรือ ERP อยู่แล้ว</div>\n                            </div>\n                        </div>\n                    </div>\n\n                    <div class="product-box">\n                        <div class="product-box-header">\n                            <span class="product-box-badge light">Mid-Tier</span>\n                            <h3 class="product-box-title">SFT</h3>\n                            <p class="product-box-tagline">ติดตามหน้างานโดยไม่ต้องซับซ้อนเท่า MES</p>\n                        </div>\n                        <div class="product-box-content">\n                            <p class="product-box-desc">ระบบติดตามเบาๆ สำหรับโรงงานที่ต้องการมองเห็นโดยไม่ต้องซับซ้อนเท่า MES เต็มรูปแบบ ใช้บาร์โค้ด ติดตั้งเร็ว ใช้งานง่าย</p>\n                            <ul class="product-features">\n                                <li><span class="check">✓</span> รายงานปริมาณการผลิต</li>\n                                <li><span class="check">✓</span> ติดตามเวลาแรงงานตาม Operation</li>\n                                <li><span class="check">✓</span> บันทึกสาเหตุหยุดเครื่อง</li>\n                                <li><span class="check">✓</span> ตรวจสอบย้อนกลับระดับล็อตเบื้องต้น</li>\n                                <li><span class="check">✓</span> หน้าจอสแกนบาร์โค้ดใช้ง่าย</li>\n                                <li><span class="check">✓</span> ติดตั้งเร็ว (เป็นวัน ไม่ใช่เป็นเดือน)</li>\n                            </ul>\n                            <div class="product-best-for">\n                                <div class="product-best-for-label">เหมาะสำหรับ</div>\n                                <div class="product-best-for-text">โรงงานที่ใช้ SCADA อยู่แล้ว, บริษัทเติบโตเร็ว, ต้องการเพิ่มการมองเห็นอย่างรวดเร็วโดยไม่รบกวนการผลิต</div>\n                            </div>\n                        </div>\n                    </div>\n\n                    <div class="product-box">\n                        <div class="product-box-header">\n                            <span class="product-box-badge entry">Entry Level</span>\n                            <h3 class="product-box-title">AIoT Cloud</h3>\n                            <p class="product-box-tagline">มองเห็นการผลิตแบบสมัครสมาชิก</p>\n                        </div>\n                        <div class="product-box-content">\n                            <p class="product-box-desc">ระบบตรวจสอบการผลิตบนคลาวด์พร้อมแอปมือถือ ดูข้อมูลเครื่องจักรและสถานะการผลิตโดยไม่ต้องลงทุนโครงสร้าง IT</p>\n                            <ul class="product-features">\n                                <li><span class="check">✓</span> ตรวจสอบเครื่องจักรแบบเรียลไทม์</li>\n                                <li><span class="check">✓</span> แดชบอร์ดสถานะการผลิต</li>\n                                <li><span class="check">✓</span> เข้าถึงผ่านแอปมือถือ</li>\n                                <li><span class="check">✓</span> ราคาแบบสมัครสมาชิก (ไม่ต้องลงทุนล่วงหน้า)</li>\n                                <li><span class="check">✓</span> ติดตั้งบนคลาวด์ (ไม่ต้องมีเซิร์ฟเวอร์)</li>\n                            </ul>\n                            <div class="product-best-for">\n                                <div class="product-best-for-label">เหมาะสำหรับ</div>\n                                <div class="product-best-for-text">เริ่มต้นลงทุนน้อย, ตรวจสอบเครื่องจักรเบื้องต้น, โรงงานที่ต้องการทดลองดิจิทัลก่อนตัดสินใจเต็มตัว</div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n    \n                <div class="selection-guide">\n                    <div class="selection-guide-item">\n                        <div class="selection-guide-arrow">▲</div>\n                        <div class="selection-guide-product">AIoT Cloud</div>\n                        <div class="selection-guide-desc">เริ่มต้นการเดินทางดิจิทัล โรงงานเล็ก เริ่มเร็ว ราคาสมัครสมาชิก</div>\n                    </div>\n                    <div class="selection-guide-item">\n                        <div class="selection-guide-arrow">▲▲</div>\n                        <div class="selection-guide-product">SFT</div>\n                        <div class="selection-guide-desc">ต้องการความโปร่งใสในการผลิต ปฏิบัติการขนาดกลาง ติดตามเป็นระบบ ติดตั้งเร็ว</div>\n                    </div>\n                    <div class="selection-guide-item">\n                        <div class="selection-guide-arrow">▲▲▲</div>\n                        <div class="selection-guide-product">MES</div>\n                        <div class="selection-guide-desc">บริหารการผลิตเต็มรูปแบบ ปฏิบัติการซับซ้อน หลายโรงงาน ตรวจสอบย้อนกลับครบวงจร</div>\n                    </div>\n                </div>\n    \n                <div class="erp-compat-callout">\n                    <div class="erp-compat-icon">\n                        <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v6m0 8v6M4.93 4.93l4.24 4.24m5.66 5.66l4.24 4.24M2 12h6m8 0h6M4.93 19.07l4.24-4.24m5.66-5.66l4.24-4.24"/></svg>\n                    </div>\n                    <div class="erp-compat-content">\n                        <h3>มี ERP อยู่แล้ว?</h3>\n                        <p>MES เชื่อมต่อกับ ERP ทุกระบบผ่าน Web Services มาตรฐาน มองเห็นสายการผลิตของคุณชัดเจน โดยไม่ต้องเปลี่ยน ERP เดิม เมื่อพร้อมอัปเกรด เราอยู่ตรงนี้</p>\n                    </div>\n                </div>\n    \n                <div class="workflow-strip">\n                    <h3 class="workflow-strip-title">วันหนึ่งบนสายการผลิตที่เชื่อมต่อ MES</h3>\n                    <div class="workflow-steps">\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">1</div>\n                            <div class="workflow-step-label">ลงเวลาเข้า</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">2</div>\n                            <div class="workflow-step-label">ตรวจวัตถุดิบ</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">3</div>\n                            <div class="workflow-step-label">QC ครั้งแรก</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">4</div>\n                            <div class="workflow-step-label">เริ่มเครื่อง</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">5</div>\n                            <div class="workflow-step-label">บันทึกการผลิต</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">6</div>\n                            <div class="workflow-step-label">QC กลางกะ</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">7</div>\n                            <div class="workflow-step-label">เบิกวัตถุดิบ</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">8</div>\n                            <div class="workflow-step-label">นับชิ้นงาน</div>\n                        </div>\n                        <div class="workflow-connector"></div>\n                        <div class="workflow-step">\n                            <div class="workflow-step-circle">9</div>\n                            <div class="workflow-step-label">ลงเวลาออก</div>\n                        </div>\n                        \n                    </div>\n                    <p class="workflow-caption">“ทุกขั้นตอนถูกบันทึก ทุกการสแกนถูกเก็บ ทุกนาทีถูกนับ”</p>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="capabilities-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <line x1="0" y1="450" x2="1400" y2="450" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n                    <rect x="150" y="400" width="80" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="190" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">WS-01</text>\n                    <path d="M230 450 L380 450" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="375,445 390,450 375,455" fill="#000864" opacity="0.12"/>\n                    <rect x="390" y="400" width="80" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="430" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">WS-02</text>\n                    <path d="M470 450 L620 450" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="615,445 630,450 615,455" fill="#000864" opacity="0.12"/>\n                    <rect x="630" y="400" width="80" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="670" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">WS-03</text>\n                    <path d="M710 450 L860 450" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="855,445 870,450 855,455" fill="#000864" opacity="0.12"/>\n                    <rect x="870" y="400" width="80" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="910" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">QC</text>\n                    <path d="M950 450 L1100 450" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="1095,445 1110,450 1095,455" fill="#000864" opacity="0.12"/>\n                    <rect x="1110" y="400" width="80" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="1150" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">PACK</text>\n                    <circle cx="190" cy="300" r="20" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.12"/>\n                    <text x="190" y="304" font-family="\'Noto Sans\',sans-serif" font-size="7" fill="#00AFF0" opacity="0.15" text-anchor="middle">SCAN</text>\n                    <circle cx="430" cy="300" r="20" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.12"/>\n                    <circle cx="670" cy="300" r="20" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.12"/>\n                    <circle cx="910" cy="300" r="20" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.12"/>\n                    <rect x="500" y="600" width="400" height="40" rx="4" stroke="#000864" stroke-width="1" fill="none" opacity="0.08"/>\n                    <text x="700" y="625" font-family="\'Noto Sans\',sans-serif" font-size="10" font-weight="600" fill="#000864" opacity="0.06" text-anchor="middle">WORK ORDER TRACKING</text>\n                    <circle cx="300" cy="700" r="3" fill="#000864" opacity="0.08"/>\n                    <circle cx="1200" cy="250" r="4" fill="#000864" opacity="0.08"/>\n                </svg>\n            </div>\n            <div class="products-inner" style="position: relative; z-index: 2;">\n                <div class="section-header">\n                    <h2 class="section-title">สิ่งที่คุณมองเห็นได้—ตอนนี้เลย</h2>\n                    <p class="section-subtitle">มองเห็นทุกด้านของการผลิตแบบเรียลไทม์</p>\n                </div>\n    \n                <div class="capabilities-grid">\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="10" r="3"/><path d="M12 2a8 8 0 0 0-8 8c0 5.4 7 11.5 7.3 11.8a1 1 0 0 0 1.4 0C13 21.5 20 15.4 20 10a8 8 0 0 0-8-8z"/></svg></div>\n                        <h3 class="capability-title">ตำแหน่งออเดอร์</h3>\n                        <p class="capability-desc">อยู่สถานีไหน? ทำ Operation อะไร? อีกนานแค่ไหนถึงเสร็จ?</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M3 3v18h18"/><path d="M18.7 8l-5.1 5.2-2.8-2.7L7 14.3"/></svg></div>\n                        <h3 class="capability-title">อัตราการผลิต</h3>\n                        <p class="capability-desc">ชิ้นงานต่อชั่วโมง เทียบกับเป้า แยกตามสาย, สินค้า, กะ</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg></div>\n                        <h3 class="capability-title">ปัญหาคุณภาพ</h3>\n                        <p class="capability-desc">ข้อบกพร่องทันทีที่เกิด แยกตามประเภท สถานี พนักงาน</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg></div>\n                        <h3 class="capability-title">Downtime</h3>\n                        <p class="capability-desc">อะไรหยุด? ทำไม? นานเท่าไหร่? แนวโน้มตลอดช่วงเวลา</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg></div>\n                        <h3 class="capability-title">ประสิทธิภาพแรงงาน</h3>\n                        <p class="capability-desc">เวลาจริง vs. มาตรฐาน แยกตามพนักงาน แยกตาม Operation</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><polyline points="3.27 6.96 12 12.01 20.73 6.96"/><line x1="12" y1="22.08" x2="12" y2="12"/></svg></div>\n                        <h3 class="capability-title">การใช้วัตถุดิบ</h3>\n                        <p class="capability-desc">กำลังใช้อะไรอยู่? ผลต่างจากมาตรฐานเท่าไหร่?</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18"/><path d="M9 21V9"/></svg></div>\n                        <h3 class="capability-title">ดัชนี OEE</h3>\n                        <p class="capability-desc">Availability, Performance, Quality—คำนวณอัตโนมัติ</p>\n                    </div>\n                    <div class="capability-card">\n                        <div class="capability-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg></div>\n                        <h3 class="capability-title">ตรวจสอบย้อนกลับ</h3>\n                        <p class="capability-desc">ประวัติครบวงจร ล็อต ซีเรียล ชิ้นส่วน พนักงาน</p>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="integration-section">\n    <div class="integration-inner" style="position: relative; z-index: 2;">\n                <div class="section-header">\n                    <h2 class="section-title">เชื่อมต่อกับทุกอย่าง</h2>\n                    <p class="section-subtitle">MES คือสะพานเชื่อมระหว่างการวางแผนกับการปฏิบัติงาน</p>\n                </div>\n    \n                <div class="integration-visual">\n                    <div class="integration-node">\n                        <div class="integration-node-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18"/><path d="M9 21V9"/></svg>\n                        </div>\n                        <div class="integration-node-name">ERP</div>\n                    </div>\n                    <div class="integration-arrow">↔</div>\n                    <div class="integration-node active">\n                        <div class="integration-node-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="7" width="20" height="14" rx="2"/><path d="M6 7V5a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v2"/><line x1="6" y1="12" x2="6" y2="12"/><line x1="10" y1="12" x2="10" y2="12"/><line x1="14" y1="12" x2="14" y2="12"/><line x1="18" y1="12" x2="18" y2="12"/></svg>\n                        </div>\n                        <div class="integration-node-name">MES</div>\n                    </div>\n                    <div class="integration-arrow">↔</div>\n                    <div class="integration-node">\n                        <div class="integration-node-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/></svg>\n                        </div>\n                        <div class="integration-node-name">WMS</div>\n                    </div>\n                    <div class="integration-arrow">↔</div>\n                    <div class="integration-node">\n                        <div class="integration-node-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4"/></svg>\n                        </div>\n                        <div class="integration-node-name">AIoT</div>\n                    </div>\n                </div>\n    \n                <div class="integration-message">\n                    <p>ใบสั่งผลิตไหลจาก ERP สู่ MES อัตโนมัติ การใช้วัตถุดิบอัปเดตสินค้าคงคลังแบบเรียลไทม์ ข้อมูลเครื่องจักรจาก AIoT ป้อนการคำนวณ OEE <strong>ระบบเดียวเชื่อมต่อ ไม่ต้องกระทบยอดด้วยมือ</strong></p>\n                </div>\n    \n                <div class="integration-links">\n                    <a href="erp.html" class="integration-link">สำรวจ ERP →</a>\n                    <a href="wms.html" class="integration-link">สำรวจ WMS →</a>\n                    <a href="aiot.html" class="integration-link">สำรวจ AIoT →</a>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Results (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Results (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Results (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="results-section" data-particles="bold">\n    <div class="results-inner" style="position: relative; z-index: 2;">\n                <div class="results-header">\n                    <p class="results-label">ผลลัพธ์ที่วัดได้</p>\n                    <h2 class="results-title">สิ่งที่ลูกค้าของเราทำได้</h2>\n                </div>\n    \n                <p class="results-row-label">ผลลัพธ์ MES</p>\n                <div class="results-grid">\n                    <div class="result-card">\n                        <div class="result-value">-45%</div>\n                        <div class="result-label">รอบเวลาการผลิต</div>\n                    </div>\n                    <div class="result-card">\n                        <div class="result-value">-70%</div>\n                        <div class="result-label">อัตราข้อบกพร่องด้านคุณภาพ</div>\n                    </div>\n                    <div class="result-card">\n                        <div class="result-value">+26%</div>\n                        <div class="result-label">ประสิทธิภาพการดำเนินงาน</div>\n                    </div>\n                </div>\n    \n                <p class="results-row-label">ผลลัพธ์ SFT</p>\n                <div class="results-grid">\n                    <div class="result-card">\n                        <div class="result-value">92%</div>\n                        <div class="result-label">ความโปร่งใสของการผลิต</div>\n                    </div>\n                    <div class="result-card">\n                        <div class="result-value">86%</div>\n                        <div class="result-label">อัตราส่งมอบตรงเวลา</div>\n                    </div>\n                    <div class="result-card">\n                        <div class="result-value">2-4</div>\n                        <div class="result-label">สัปดาห์ในการติดตั้ง</div>\n                    </div>\n                </div>\n    \n                <div class="results-shared">\n                    <div class="result-card">\n                        <div class="result-value">76%</div>\n                        <div class="result-label">การปรับปรุงความพึงพอใจลูกค้า</div>\n                    </div>\n                </div>\n    \n                <p class="results-attribution">อ้างอิงจากข้อมูลการติดตั้ง DigiWin จากลูกค้าด้านการผลิตกว่า 50,000+ ราย</p>\n            </div>\n    \n<script>\n(function(){\n  \'use strict\';\n  var reducedMotion=window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\n  var PI2=Math.PI*2;\n  var BLUE=[0,175,240],CYAN=[0,230,255];\n  var PRESETS={\n    subtle:{frontOpacity:0.30,backOpacity:0.04,frontRadius:4.5,backRadius:0.6,color:BLUE,colorAlt:CYAN,altRatio:0.12},\n    medium:{frontOpacity:0.45,backOpacity:0.06,frontRadius:5.0,backRadius:0.8,color:BLUE,colorAlt:CYAN,altRatio:0.18},\n    bold:{frontOpacity:0.60,backOpacity:0.10,frontRadius:5.5,backRadius:1.0,color:CYAN,colorAlt:BLUE,altRatio:0.25}\n  };\n  function lerp(a,b,t){return a+(b-a)*t}\n  function DataOcean(el){\n    this.el=el;this.canvas=null;this.ctx=null;this.w=0;this.h=0;\n    this.dpr=Math.min(window.devicePixelRatio||1,2);this.visible=false;this.raf=null;this.time=0;this.resizeTimer=null;this.colors=null;\n    this.opts=this._parseOpts();this._setup();this._buildColors();this._observe();\n    if(!reducedMotion){this._loop()}else{this.visible=true;this._draw(0)}\n  }\n  DataOcean.prototype._parseOpts=function(){var n=this.el.getAttribute(\'data-particles\')||\'subtle\';if(n===\'\'||n===\'true\')n=\'subtle\';return PRESETS[n]||PRESETS.subtle};\n  DataOcean.prototype._setup=function(){\n    var c=document.createElement(\'canvas\');c.setAttribute(\'aria-hidden\',\'true\');\n    c.style.cssText=\'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\n    var pos=getComputedStyle(this.el).position;if(pos===\'static\')this.el.style.position=\'relative\';\n    this.el.style.overflow=\'hidden\';this.el.insertBefore(c,this.el.firstChild);this.canvas=c;this.ctx=c.getContext(\'2d\');this._resize();\n    var self=this;window.addEventListener(\'resize\',function(){clearTimeout(self.resizeTimer);self.resizeTimer=setTimeout(function(){self._resize();self._buildColors()},200)});\n  };\n  DataOcean.prototype._resize=function(){var r=this.el.getBoundingClientRect();this.w=r.width;this.h=r.height;this.canvas.width=this.w*this.dpr;this.canvas.height=this.h*this.dpr;this.ctx.setTransform(this.dpr,0,0,this.dpr,0,0)};\n  DataOcean.prototype._buildColors=function(){var cols=Math.min(65,Math.ceil(this.w/22)+4);var rows=35;this._cols=cols;this._rows=rows;var n=cols*rows;this.colors=new Array(n);var alt=this.opts.altRatio;for(var i=0;i<n;i++){this.colors[i]=Math.random()<alt?this.opts.colorAlt:this.opts.color}};\n  DataOcean.prototype._observe=function(){var self=this;if(\'IntersectionObserver\' in window){this._obs=new IntersectionObserver(function(e){self.visible=e[0].isIntersecting},{rootMargin:\'150px 0px\'});this._obs.observe(this.el)}else{this.visible=true}};\n  DataOcean.prototype._loop=function(){var self=this;var last=0;(function tick(ts){self.raf=requestAnimationFrame(tick);if(!self.visible)return;if(ts-last<30)return;last=ts;self.time+=0.006;self._draw(self.time)})(0)};\n  DataOcean.prototype._draw=function(t){\n    var ctx=this.ctx,w=this.w,h=this.h,opts=this.opts,cols=this._cols,rows=this._rows;\n    ctx.clearRect(0,0,w,h);var ground=h+10,horizon=h*0.35,totalSpan=ground-horizon,idx=0;\n    for(var row=rows-1;row>=0;row--){\n      var depth=row/(rows-1),mappedDepth=Math.pow(depth,0.55),baseY=ground-mappedDepth*totalSpan;\n      var dotR=lerp(opts.frontRadius,opts.backRadius,depth),dotA=lerp(opts.frontOpacity,opts.backOpacity,depth);\n      var colSpacing=lerp(w/(cols-4),w/(cols+15),depth),rowShift=depth*w*0.12;\n      var waveScale=1-depth*0.75,amp1=70*waveScale,amp2=25*waveScale;\n      for(var col=0;col<cols;col++){\n        var screenX=col*colSpacing-rowShift+colSpacing*0.5;\n        if(screenX<-30||screenX>w+30){idx++;continue}\n        var worldX=col*24,worldZ=row*18;\n        var wave=amp1*Math.sin(worldX*0.0065+worldZ*0.012+t*0.9);\n        wave+=amp2*Math.sin(worldX*0.013-worldZ*0.008+t*0.55+1.8);\n        var screenY=baseY-wave;if(screenY<-15||screenY>h+15){idx++;continue}\n        var c=this.colors[idx%this.colors.length];\n        ctx.beginPath();ctx.arc(screenX,screenY,dotR,0,PI2);\n        ctx.fillStyle=\'rgba(\'+c[0]+\',\'+c[1]+\',\'+c[2]+\',\'+dotA+\')\';ctx.fill();idx++;\n      }\n    }\n  };\n  DataOcean.prototype.destroy=function(){if(this.raf)cancelAnimationFrame(this.raf);if(this._obs)this._obs.disconnect();if(this.canvas&&this.canvas.parentNode)this.canvas.parentNode.removeChild(this.canvas)};\n  function init(){var els=document.querySelectorAll(\'[data-particles]\');for(var i=0;i<els.length;i++)new DataOcean(els[i])}\n  if(document.readyState===\'loading\')document.addEventListener(\'DOMContentLoaded\',init);else init();\n})();\n</script>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Reports (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Reports (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Reports (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="reports-section">\n    <div class="reports-inner">\n                <div class="section-header">\n                    <h2 class="section-title">รายงานและแดชบอร์ดในตัว</h2>\n                    <p class="section-subtitle">ระบบวิเคราะห์สำเร็จรูปพร้อมใช้ตั้งแต่วันแรก — ไม่ต้องพัฒนาเพิ่ม</p>\n                </div>\n    \n                <div class="reports-grid">\n                    <div class="reports-column">\n                        <div class="reports-column-header">\n                            <span class="reports-column-badge">MES</span>\n                            <span class="reports-column-count">10 รายงาน</span>\n                        </div>\n                        <ol class="reports-list">\n                            <li><span class="report-icon">&#9632;</span> ความคืบหน้าใบสั่งผลิต</li>\n                            <li><span class="report-icon">&#9632;</span> การใช้งานเครื่องจักร (OEE)</li>\n                            <li><span class="report-icon">&#9632;</span> การตรวจสอบคุณภาพ</li>\n                            <li><span class="report-icon">&#9632;</span> การใช้วัตถุดิบ</li>\n                            <li><span class="report-icon">&#9632;</span> ประสิทธิภาพกะ</li>\n                            <li><span class="report-icon">&#9632;</span> วิเคราะห์ Downtime</li>\n                            <li><span class="report-icon">&#9632;</span> อัตราผลผลิต</li>\n                            <li><span class="report-icon">&#9632;</span> รอบเวลาการผลิต</li>\n                            <li><span class="report-icon">&#9632;</span> ตรวจสอบย้อนกลับแบทช์</li>\n                            <li><span class="report-icon">&#9632;</span> ผลิตภาพพนักงาน</li>\n                        </ol>\n                    </div>\n    \n                    <div class="reports-column">\n                        <div class="reports-column-header">\n                            <span class="reports-column-badge sft">SFT</span>\n                            <span class="reports-column-count">6 แดชบอร์ด</span>\n                        </div>\n                        <ol class="reports-list">\n                            <li><span class="report-icon">&#9632;</span> บอร์ดสถานะการผลิต</li>\n                            <li><span class="report-icon">&#9632;</span> สรุปผลผลิตรายวัน</li>\n                            <li><span class="report-icon">&#9632;</span> ตรวจสอบสถานะเครื่องจักร</li>\n                            <li><span class="report-icon">&#9632;</span> ความสำเร็จของออเดอร์</li>\n                            <li><span class="report-icon">&#9632;</span> ติดตาม WIP</li>\n                            <li><span class="report-icon">&#9632;</span> ตารางการจัดส่ง</li>\n                        </ol>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: MES (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: MES (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: MES (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="th-mes-faq">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n            <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #000864; margin-bottom: 32px; text-align: center;">Frequently Asked Questions</h2>\n            <div style="display: flex; flex-direction: column; gap: 12px;">\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">MES (ระบบบริหารการผลิต) คืออะไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">MES (Manufacturing Execution System — ระบบบริหารการผลิต) คือซอฟต์แวร์ที่ติดตาม ตรวจสอบ และควบคุมการผลิตบนพื้นที่โรงงานแบบเรียลไทม์ เชื่อมช่องว่างระหว่างการวางแผนใน ERP กับการปฏิบัติงานจริงหน้างาน — ช่วยให้คุณเห็นสิ่งที่เกิดขึ้นบนเครื่องจักรและสถานีงานทุกแห่งตอนนี้ ไม่ใช่เมื่อวาน</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">MES, SFT, และ AIoT Cloud ต่างกันอย่างไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">MES คือระบบบริหารการผลิตเต็มรูปแบบของ DigiWin สำหรับการจัดการการผลิตครบวงจร — ติดตามใบสั่งผลิต, ควบคุมคุณภาพ, ตรวจสอบย้อนกลับวัตถุดิบ, และวิเคราะห์ OEE SFT (Shop Floor Tracking — ติดตามหน้างาน) เป็นตัวเลือกระดับกลาง ติดตั้งภายใน 2-4 สัปดาห์ เน้นรายงานการผลิตและตรวจสอบสถานะเครื่องจักร AIoT Cloud เป็นระดับเริ่มต้น — ตรวจสอบบนคลาวด์พร้อมแอปมือถือและราคาแบบสมัครสมาชิก หลายโรงงานเริ่มจาก AIoT Cloud หรือ SFT แล้วขยายไปสู่ MES เต็มรูปแบบเมื่อพร้อม</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">จำเป็นต้องมี ERP ก่อนจึงจะใช้ MES ได้หรือไม่?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">ไม่จำเป็น DigiWin MES เชื่อมต่อกับ ERP ที่มีอยู่ทุกระบบผ่าน Web Services มาตรฐาน ผู้ผลิตหลายรายเริ่มจาก MES ก่อนเพื่อให้มองเห็นสายการผลิตได้ทันที แล้วค่อยเพิ่มหรืออัปเกรด ERP ทีหลัง วิธีนี้ทำให้คุณเห็นผลตอบแทนเร็วกว่าการเปลี่ยน ERP ทั้งระบบ</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">ผลลัพธ์ที่คาดหวังจาก DigiWin MES เป็นอย่างไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">จากข้อมูลการติดตั้งจากลูกค้าด้านการผลิตกว่า 50,000+ ราย ลูกค้า MES รายงานว่ารอบเวลาการผลิตลดลง 45%, อัตราข้อบกพร่องด้านคุณภาพลดลง 70%, และประสิทธิภาพการดำเนินงานเพิ่มขึ้น 26% ผู้ใช้ SFT มักทำได้ถึงความโปร่งใสของการผลิต 92% และอัตราส่งมอบตรงเวลา 86% ผลลัพธ์แตกต่างตามโรงงาน แต่การมองเห็นเพียงอย่างเดียวก็มักจะนำไปสู่การปรับปรุงพฤติกรรมบนสายการผลิตทันที</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin MES เชื่อมต่อกับเครื่องจักรหน้างานอย่างไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin MES เชื่อมต่อกับเครื่องจักรหน้างานผ่านแพลตฟอร์ม AIoT ของ DigiWin ซึ่งรองรับโปรโตคอลอุตสาหกรรมกว่า 50+ รายการ ได้แก่ OPC-UA, Modbus, MQTT, และการเชื่อมต่อ CNC/PLC โดยตรง สำหรับเครื่องจักรที่ไม่มีอินเทอร์เฟซดิจิทัล การสแกนบาร์โค้ดและการกรอกข้อมูลผ่านแท็บเล็ตจะเป็นสะพานเชื่อมข้อมูล</p>\n                </div>\n              </details>\n            </div>\n          </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: พร้อมมองเห็นสายการผลิตชัดเจนหรือยัง?"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: พร้อมมองเห็นสายการผลิตชัดเจนหรือยัง?: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: พร้อมมองเห็นสายการผลิตชัดเจนหรือยัง?: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="th-mes-cta-section">\n    <div class="th-mes-cta-super-d" aria-hidden="true"></div>\n    \n    <div class="th-mes-cta-container">\n      <h2 class="th-mes-cta-title">พร้อมมองเห็นสายการผลิตชัดเจนหรือยัง?</h2>\n      <p class="th-mes-cta-subtitle">กรอกแบบฟอร์ม ทีมงานจะติดต่อกลับเพื่อพูดคุยเรื่องความท้าทายด้านการมองเห็นการผลิตของคุณ</p>\n      <div class="th-mes-cta-btn-row">\n        <a href="/th/demo/" class="th-mes-cta-btn th-mes-cta-btn--primary">ติดต่อเรา</a>\n        <a href="/industries.html" class="th-mes-cta-btn th-mes-cta-btn--ghost">ดูตามอุตสาหกรรม</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Column"}}},"decoration":{}}} -->\n<!-- wp:html --><style>\n.th-mes-related-grid{display:grid!important;grid-template-columns:repeat(auto-fit,minmax(280px,1fr))!important;gap:24px!important;max-width:1200px!important;margin:0 auto!important}\n.th-mes-related-card{display:block!important;padding:24px!important;background:#fff!important;border-radius:12px!important;text-decoration:none!important;border:1px solid #e5e7eb!important;color:#333!important;line-height:1.6!important}\n.th-mes-related-card-title{font-size:18px!important;font-weight:600!important;color:#000864!important;margin:0 0 8px 0!important}\n.th-mes-related-card-desc{font-size:14px!important;color:#666!important;margin:0!important}\n</style><div class="th-mes-related-section">\n    <h2 class="th-mes-related-heading">Explore Related Solutions</h2>\n    <div class="th-mes-related-grid">\n      <a href="/products/erp/" class="th-mes-related-card">\n        <h3 class="th-mes-related-card-title">ERP</h3>\n        <p class="th-mes-related-card-desc">ระบบ ERP ครบวงจรสำหรับโรงงานไทย — ตั้งแต่ BOM จนถึงบัญชีการเงินและรองรับ BOI</p>\n      </a>\n      <a href="/products/wms/" class="th-mes-related-card">\n        <h3 class="th-mes-related-card-title">WMS</h3>\n        <p class="th-mes-related-card-desc">ระบบจัดการคลังสินค้าอัจฉริยะด้วยบาร์โค้ด/RFID — ตั้งแต่รับของจนถึงจัดส่ง ตรวจสอบย้อนกลับครบวงจร</p>\n      </a>\n      <a href="/products/aiot/" class="th-mes-related-card">\n        <h3 class="th-mes-related-card-title">AIoT</h3>\n        <p class="th-mes-related-card-desc">เชื่อมต่อเครื่องจักรเข้ากับ ERP โดยตรงด้วยเซ็นเซอร์ IoT, Edge Computing, และการวิเคราะห์ด้วย AI</p>\n      </a>\n      <a href="/industries/automotive/" class="th-mes-related-card">\n        <h3 class="th-mes-related-card-title">ชิ้นส่วนยานยนต์</h3>\n        <p class="th-mes-related-card-desc">ERP และ MES ที่ออกแบบเฉพาะสำหรับผู้ผลิตชิ้นส่วนยานยนต์และซัพพลายเออร์ OEM</p>\n      </a>\n      <a href="/industries/electronics/" class="th-mes-related-card">\n        <h3 class="th-mes-related-card-title">อิเล็กทรอนิกส์</h3>\n        <p class="th-mes-related-card-desc">ซอฟต์แวร์การผลิตสำหรับประกอบอิเล็กทรอนิกส์ สาย SMT และตรวจสอบย้อนกลับชิ้นส่วน</p>\n      </a>\n      <a href="/industries/metal-plastics/" class="th-mes-related-card">\n        <h3 class="th-mes-related-card-title">โลหะและพลาสติก</h3>\n        <p class="th-mes-related-card-desc">โซลูชันครบวงจรสำหรับหล่อขึ้นรูป ฉีดพลาสติก และงานแปรรูปโลหะ</p>\n      </a>\n    </div>\n  </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100778;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100778 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100778, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === HERO (S1) === */\n/* TODO: Review and remap class selectors to use hero prefix */\n/* TODO: Add section container: .hero-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.mes-hero {\n            background: linear-gradient(135deg, #1a2d3d 0%, #000864 50%, #001080 100%);\n            padding: 140px 0 100px;\n            position: relative;\n            overflow: hidden;\n        }\n.mes-hero::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            bottom: 0;\n            background: url(\'data:image/svg+xml,<svg aria-hidden="true" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><defs><pattern id="grid" width="10" height="10" patternUnits="userSpaceOnUse"><path d="M 10 0 L 0 0 0 10" fill="none" stroke="rgba(255,255,255,0.03)" stroke-width="0.5"/></pattern></defs><rect width="100" height="100" fill="url(%23grid)"/></svg>\');\n            opacity: 0.5;\n        }\n.mes-hero-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 24px;\n            text-align: center;\n            position: relative;\n            z-index: 1;\n        }\n.mes-hero-badge {\n            display: inline-flex;\n            align-items: center;\n            gap: 8px;\n            background: rgba(0, 175, 240, 0.15);\n            border: 1px solid rgba(0, 175, 240, 0.3);\n            padding: 8px 20px;\n            border-radius: 50px;\n            color: #7fc4fd;\n            font-size: 11px;\n            font-weight: 500;\n            margin-bottom: 24px;\n            font-family: \'JetBrains Mono\', monospace;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n        \n            line-height: 17.6px;\n\n            -webkit-font-smoothing: auto;\n}\n.mes-hero-stats {\n            display: flex;\n            justify-content: center;\n            gap: 48px;\n            margin-top: 40px;\n            padding-top: 32px;\n            border-top: 1px solid rgba(255, 255, 255, 0.1);\n        }\n.mes-hero-stat-number {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 32px;\n            font-weight: 800;\n            color: #00AFF0;\n        \n            line-height: 51.2px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.mes-hero-stat-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            color: rgba(255, 255, 255, 0.75);\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            margin-top: 4px;\n        \n            line-height: 16px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n.mes-hero-grid {\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 60px;\n            align-items: center;\n            text-align: left;\n        }\n.mes-hero-content {\n            max-width: 560px;\n        }\n.mes-hero-visual {\n            position: relative;\n        }\n.mes-dashboard-mockup {\n            background: rgba(255, 255, 255, 0.03);\n            border: 1px solid rgba(