der-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.th-mes-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.th-mes-cta-btn:hover::before{left:100%}\n.th-mes-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.th-mes-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.th-mes-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.th-mes-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.th-mes-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.th-mes-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .th-mes-cta-title{font-size:28px;margin-bottom:16px}\n  .th-mes-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .th-mes-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .th-mes-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.th-mes-cta-btn{transition:none !important}.th-mes-cta-btn::before{display:none}}\n\n.et_pb_section:has(.th-mes-related-section){background:#F5F7FA;padding:0}\n.th-mes-related-section{padding:60px 5%;background:#F5F7FA;max-width:100%;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto}\n.th-mes-related-heading{font-family:\'Noto Sans\',sans-serif;font-size:28px;font-weight:600;color:#000864;margin:0 0 32px 0;padding:0;text-align:center;line-height:1.6;-webkit-font-smoothing:auto}\n.th-mes-related-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap